#!/usr/bin/env bash
# Test Result Gate — runs as the LAST step of each module job, AFTER the
# report-upload and module-email steps (so evidence always ships first).
#
# The "Run X Tests" mvn steps keep continue-on-error: true so artifacts,
# emails and the failed-suite collector still get a completed job; THIS step
# is what turns the job red. It fails loudly when:
#   1. no testng-results.xml was produced (mvn died / suite never ran)
#   2. any test failed
#   3. zero tests actually executed (total - skipped == 0): mass-skip or a
#      disabled suite silently advertising a green job
#
# Usage: test-result-gate.sh [report-dir]   (default: target/surefire-reports)
# Parsing: xmllint (preinstalled on macOS) with python3 stdlib fallback.
set -u

DIR="${1:-target/surefire-reports}"
XML="$DIR/testng-results.xml"

if [ ! -f "$XML" ]; then
  echo "::error::No test results produced — $XML is missing (suite never ran?)"
  exit 1
fi

TOTAL="" FAILED="" SKIPPED=""

if command -v xmllint >/dev/null 2>&1; then
  TOTAL=$(xmllint --xpath 'string(/testng-results/@total)' "$XML" 2>/dev/null || true)
  FAILED=$(xmllint --xpath 'string(/testng-results/@failed)' "$XML" 2>/dev/null || true)
  SKIPPED=$(xmllint --xpath 'string(/testng-results/@skipped)' "$XML" 2>/dev/null || true)
fi

if [ -z "$TOTAL" ]; then
  # Fallback: python3. Prefers defusedxml (XXE-safe, repo convention) but the
  # gate must work with NO pip installs, so stdlib is the last resort — the
  # XML is locally generated by surefire on this runner, not attacker input.
  COUNTS=$(python3 - "$XML" <<'PY' 2>/dev/null || true
import sys
try:
    import defusedxml.ElementTree as ET
except ImportError:
    import xml.etree.ElementTree as ET
r = ET.parse(sys.argv[1]).getroot()
print(r.get("total", ""), r.get("failed", ""), r.get("skipped", ""))
PY
)
  read -r TOTAL FAILED SKIPPED <<< "$COUNTS"
fi

case "$TOTAL" in
  ''|*[!0-9]*) echo "::error::Could not parse test counts from $XML"; exit 1 ;;
esac
FAILED=${FAILED:-0}; SKIPPED=${SKIPPED:-0}
case "$FAILED"  in ''|*[!0-9]*) FAILED=0  ;; esac
case "$SKIPPED" in ''|*[!0-9]*) SKIPPED=0 ;; esac

EXECUTED=$((TOTAL - SKIPPED))
echo "Test Result Gate: total=$TOTAL failed=$FAILED skipped=$SKIPPED executed=$EXECUTED"

if [ "$FAILED" -gt 0 ]; then
  echo "::error::$FAILED test(s) failed in $XML"
  exit 1
fi

if [ "$EXECUTED" -eq 0 ]; then
  echo "::error::0 tests executed — mass-skip or disabled suite (total=$TOTAL, skipped=$SKIPPED)"
  exit 1
fi

echo "✅ Test Result Gate passed ($EXECUTED executed, 0 failed)"
exit 0
